import React from 'react';
import './ServiceImagePlaceholder.css';

const ServiceImagePlaceholder = ({ label, sizeHint }) => {
  return (
    <section
      className="service-image-placeholder"
      aria-label={label ? `Image area: ${label}` : 'Image placeholder area'}
    >
      <div className="container">
        <div className="service-image-placeholder-card">
          <span className="service-image-placeholder-eyebrow">Your image</span>
          {label && <p className="service-image-placeholder-title">{label}</p>}
          {sizeHint && <p className="service-image-placeholder-size">{sizeHint}</p>}
          <p className="service-image-placeholder-note">
            This space is reserved for your photography or graphics. It will be replaced when you add assets.
          </p>
        </div>
      </div>
    </section>
  );
};

export default ServiceImagePlaceholder;
